import React, { useState } from 'react';
import { StyleSheet, View, TextInput, Button, Text, ActivityIndicator } from 'react-native';

const BACKEND_URL = Platform.select({
  ios: 'http://YOUR_LOCAL_IP:8000/chat', // replace with your LAN IP
  android: 'http://10.0.2.2:8000/chat',
});

export default function App() {
  const [question, setQuestion] = useState('');
  const [answer, setAnswer] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const ask = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(BACKEND_URL!, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ question }),
      });
      if (!res.ok) throw new Error(`Server ${res.status}`);
      const data = await res.json();
      setAnswer(data.answer);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>RAG Demo</Text>
      <TextInput
        style={styles.input}
        placeholder="Ask a question..."
        value={question}
        onChangeText={setQuestion}
      />
      <Button title="Ask" onPress={ask} disabled={loading || !question} />
      {loading && <ActivityIndicator size="large" style={styles.loader} />}
      {error && <Text style={styles.error}>Error: {error}</Text>}
      {answer && (
        <View style={styles.answerBox}>
          <Text style={styles.answerLabel}>Answer:</Text>
          <Text>{answer}</Text>
        </View>
      )}
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, justifyContent: 'center', padding: 20 },
  title: { fontSize: 24, fontWeight: 'bold', marginBottom: 20, textAlign: 'center' },
  input: { borderWidth: 1, borderColor: '#ccc', padding: 10, marginBottom: 10 },
  loader: { marginVertical: 20 },
  error: { color: 'red', marginTop: 10 },
  answerBox: { marginTop: 20, padding: 15, backgroundColor: '#f0f0f0', borderRadius: 8 },
  answerLabel: { fontWeight: 'bold', marginBottom: 5 },
});

